export type AuditReportScheduleFrequency = typeof AuditReportScheduleFrequency[keyof typeof AuditReportScheduleFrequency];


export const AuditReportScheduleFrequency = {
  daily: 'daily',
  weekly: 'weekly',
  monthly: 'monthly',
} as const;

export type AuditReportScheduleLastSendStatus = typeof AuditReportScheduleLastSendStatus[keyof typeof AuditReportScheduleLastSendStatus];


export const AuditReportScheduleLastSendStatus = {
  ok: 'ok',
  failed: 'failed',
  none: 'none',
} as const;

export interface AuditReportSchedule {
  id: number;
  frequency: AuditReportScheduleFrequency;
  recipientEmail: string;
  isActive: boolean;
  /** @nullable */
  lastSentAt?: string | null;
  lastSendStatus: AuditReportScheduleLastSendStatus;
  /** @nullable */
  lastErrorMessage?: string | null;
  /** @nullable */
  failureAcknowledgedAt?: string | null;
  /** @nullable */
  failureAcknowledgedByEmail?: string | null;
  /** Total number of send attempts (successful and failed) for this schedule. */
  sendCount: number;
  /** Number of successful deliveries for this schedule. */
  successCount: number;
  /** True when the last delivery failed and automatic retries are still pending (currentRetryAttempt < maxRetryAttempts). */
  retryInProgress: boolean;
  /** The retry attempt number of the most recent log entry (0 = initial send, 1 = first retry, etc.). */
  currentRetryAttempt: number;
  /**
     * ISO timestamp of the next scheduled retry attempt (lastLogSentAt + retryBackoffMinutes). Null when no retry is pending.
     * @nullable
     */
  nextRetryAt: string | null;
  /** Number of consecutive delivery failures since the last successful send (reset to 0 on success). */
  consecutiveFailures: number;
  /** The schedule is automatically set to inactive (paused) when consecutiveFailures reaches this threshold. */
  autoPauseAfterFailures: number;
  /** Total number of send attempts (initial + retries) for the most recent delivery cycle. 0 if the schedule has never been sent, 1 if the last delivery succeeded or failed on the first try, >1 if retries were needed. */
  lastDeliveryAttempts: number;
  /** True when the most recent successful delivery was triggered manually by an admin via "Retry Now". Null/false when the last success was automatic or there has been no successful delivery. */
  lastSuccessWasManualRetry?: boolean;
  createdAt: string;
  updatedAt: string;
}

